APP CONTRATOS EASY BYZ CREATOR
COMPONENTS - CONTRACT PREVIEW
import React from 'react';
import { BRAND, CONTRACT_TEMPLATE } from '../constants';
import { PlanType, Clause } from '../types';
interface Props {
serviceType: string;
providerName: string;
providerBrand: string;
providerAddress: string;
adminName: string;
companyName: string;
planType: PlanType;
planValue: string;
annualValue?: string;
setupFee: string;
paymentKey?: string;
zelleKey?: string;
venmoKey?: string;
paymentLink?: string;
clauses: Clause[];
hiddenFields: string[];
activationInstructions: string;
clientData?: {
fullName: string;
email: string;
cpf: string;
birthDate: string;
whatsapp: string;
address: string;
};
signature?: string;
signedAt?: string;
metadata?: {
ip: string;
location: string;
};
}
const ContractPreview: React.FC<Props> = ({
serviceType,
providerName,
providerBrand,
providerAddress,
adminName,
companyName,
planType,
planValue,
annualValue,
setupFee,
paymentKey,
zelleKey,
venmoKey,
paymentLink,
clauses,
hiddenFields,
activationInstructions,
clientData,
signature,
signedAt,
metadata
}) => {
const isVisible = (field: string) => !hiddenFields.includes(field);
const formatMoney = (val: string) => {
const clean = val?.replace(/[^\d,.]/g, '').replace(',', '.') || '0';
const parsed = parseFloat(clean) || 0;
return parsed.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};
const calculateTotalMensalContract = () => {
const clean = planValue?.replace(/[^\d,.]/g, '').replace(',', '.') || '0';
const parsed = parseFloat(clean) || 0;
return (parsed * 12).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};
return (
<div className="bg-white text-gray-800 p-6 sm:p-10 rounded-xl shadow-2xl max-w-4xl mx-auto overflow-hidden text-sm leading-relaxed border border-gray-100">
<div className="text-center mb-8">
<img src={BRAND.contractLogo} alt="Logo" className="h-20 mx-auto mb-4 object-contain" />
<h1 className="text-xl font-bold uppercase tracking-tight text-gray-900 border-b-2 border-brand-green inline-block pb-1">
{CONTRACT_TEMPLATE.title} - {serviceType?.toUpperCase()}
</h1>
</div>
code
Code
<section className="mb-6 space-y-4">
    {isVisible('providerInfo') && (
      <p>
        <strong className="text-brand-dark">CONTRATADA:</strong> 
        <span className="uppercase"> {providerName || 'PATRICIA GUIMARÃES'}</span>, operando sob a marca <strong>{providerBrand || 'EASY BYZ CREATOR'}</strong>, com sede em {providerAddress || 'Santa Ana, CA - EUA'}.
      </p>
    )}

    <div className="p-4 bg-gray-50 rounded-lg border border-gray-200">
      <h2 className="font-bold text-brand-dark mb-2 uppercase border-b border-gray-200 pb-1 text-xs">CONTRATANTE</h2>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-x-4 gap-y-2 mb-2">
        {isVisible('adminName') && (
          <p className="break-words"><strong>Nome/Razão Social:</strong> <span className="text-blue-600 font-medium">{clientData?.fullName || adminName || '____________________'}</span></p>
        )}
        {isVisible('companyName') && (
          <p className="break-words"><strong>Nome Fantasia:</strong> <span className="text-blue-600 font-medium">{companyName || '____________________'}</span></p>
        )}
        <p className="break-words"><strong>E-mail:</strong> <span className="text-gray-700">{clientData?.email || '____________________'}</span></p>
        <p><strong>CPF:</strong> {clientData?.cpf || '____________________'}</p>
        <p><strong>Data de Nascimento:</strong> {clientData?.birthDate || '____________________'}</p>
        <p><strong>WhatsApp:</strong> {clientData?.whatsapp || '____________________'}</p>
      </div>
      <div className="border-t border-gray-200 mt-2 pt-2">
        <p className="break-words w-full"><strong>Endereço:</strong> <span className="text-gray-700">{clientData?.address || '____________________'}</span></p>
      </div>
    </div>
  </section>

  {clauses.map(clause => (
    isVisible(`clause-${clause.id}`) && (
      <section key={clause.id} className="mb-4">
        <h3 className="font-bold text-gray-900 uppercase">CLÁUSULA {clause.id} – {clause.title}</h3>
        <div className="text-justify text-gray-600 mt-1 whitespace-pre-line">
          {clause.id === 1 ? clause.content.replace('[SERVICE_NAME]', serviceType?.toUpperCase() || '') :
           clause.id === 3 ? (
            <div className="space-y-2">
              <p>{clause.content}</p>
              {planType === PlanType.ANNUAL ? (
                <p>
                  3.1. O CONTRATANTE opta pelo <strong>PLANO ANUAL</strong> no valor único de <strong>${formatMoney(annualValue || '0')}</strong> + Taxa de Setup única de <strong>${formatMoney(setupFee)}</strong>.
                </p>
              ) : (
                <p>
                  3.1. O CONTRATANTE opta pelo <strong>PLANO MENSAL</strong> no valor total de <strong>${calculateTotalMensalContract()}</strong>, o qual será pago em <strong>12 parcelas mensais</strong> de <strong>${formatMoney(planValue)}</strong> + Taxa de Setup única de <strong>${formatMoney(setupFee)}</strong>.
                </p>
              )}
              <p>3.2. A Taxa de Setup destina-se exclusivamente à remuneração do trabalho manual de personalização e inserção de dados no sistema.</p>
            </div>
          ) : clause.content}
        </div>
      </section>
    )
  ))}

  {/* SÓ MOSTRA O BOX SE HOUVER INSTRUÇÕES OU CHAVES DE PAGAMENTO */}
  {(activationInstructions?.trim() || paymentKey || zelleKey || venmoKey || paymentLink) && (
    <section className="mb-6 p-5 bg-brand-green/5 rounded-xl border border-brand-green/20">
      <h3 className="font-bold text-brand-dark uppercase mb-4 text-xs border-b border-brand-green/10 pb-2">Instruções para Ativação do Serviço</h3>
      
      <div className="mb-5 space-y-2 text-xs">
        {paymentKey && !zelleKey && !venmoKey && (
          <div className="flex items-center gap-2">
            <span className="font-bold">PAGAMENTO À VISTA (PIX):</span>
            <span className="bg-white px-2 py-0.5 rounded border border-brand-green/20 text-brand-dark font-medium">{paymentKey}</span>
          </div>
        )}
        {zelleKey && (
          <div className="flex items-center gap-2">
            <span className="font-bold">ZELLE:</span>
            <span className="bg-white px-2 py-0.5 rounded border border-brand-green/20 text-brand-dark font-medium">{zelleKey}</span>
          </div>
        )}
        {venmoKey && (
          <div className="flex items-center gap-2">
            <span className="font-bold">VENMO:</span>
            <span className="bg-white px-2 py-0.5 rounded border border-brand-green/20 text-brand-dark font-medium">{venmoKey}</span>
          </div>
        )}
        {paymentLink && (
          <div className="flex flex-col gap-1 pt-1">
            <span className="font-bold">PAGAMENTO PARCELADO (Link):</span>
            <span className="text-blue-600 break-all bg-white px-2 py-1 rounded border border-brand-green/20 text-[10px]">{paymentLink}</span>
          </div>
        )}
      </div>

      {activationInstructions?.trim() && (
        <div className="space-y-4 text-[10px] sm:text-[11px] text-gray-700 leading-relaxed text-justify whitespace-pre-line">
          {activationInstructions}
        </div>
      )}
    </section>
  )}

  <div className="mt-10 pt-6 border-t border-gray-200">
    <p className="text-center font-medium mb-6 italic text-gray-500 text-xs">
      Assinatura Eletrônica: Ao prosseguir com a assinatura e pagamento, o CONTRATANTE declara ter lido e aceitado todos os termos deste instrumento.
    </p>

    {signature ? (
      <div className="flex flex-col items-center">
        <img src={signature} alt="Assinatura" className="max-h-24 w-auto mb-2" />
        <div className="text-center text-[10px] text-gray-400 font-mono">
          <p>ASSINADO DIGITALMENTE POR {(clientData?.fullName || adminName).toUpperCase()}</p>
          {signedAt && <p>DATA: {signedAt}</p>}
          {metadata && <p>IP: {metadata.ip} | GEO: {metadata.location}</p>}
          {!signedAt && <p>PREVIEW EM TEMPO REAL</p>}
        </div>
      </div>
    ) : (
      <div className="flex flex-col items-center">
        <div className="w-64 h-24 border-b border-gray-400 flex items-end justify-center pb-1">
          <span className="text-gray-300">Assinatura do Contratante</span>
        </div>
      </div>
    )}
  </div>
</div>
);
};
export default ContractPreview;
COMPONENTS - NAVBAR
import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { BRAND } from '../constants';
import { ShieldCheck, LayoutDashboard, Users, Lock } from 'lucide-react';
const Navbar: React.FC = () => {
const location = useLocation();
// Identifica se é uma rota do CLIENTE
const isClientPortal = location.pathname.startsWith('/assinar/') ||
(location.pathname.startsWith('/contrato/') && !location.state?.fromAdmin);
return (
<nav className="bg-brand-dark border-b border-white/10 p-4 sticky top-0 z-50 no-print">
<div className="max-w-6xl mx-auto flex items-center justify-between">
<div className="flex items-center gap-2">
<img src={BRAND.logo} alt="Logo" className="h-10 w-auto" />
<span className="font-bold text-lg hidden sm:block">EASY BYZ CREATOR</span>
</div>
code
Code
<div className="flex items-center gap-2 sm:gap-6">
      {!isClientPortal ? (
        <div className="flex items-center gap-4 sm:gap-6">
          <Link 
            to="/" 
            className={`flex items-center gap-2 text-sm transition-colors ${location.pathname === '/' ? 'text-brand-green font-bold' : 'text-white/70 hover:text-brand-green'}`}
          >
            <LayoutDashboard size={18} />
            <span className="hidden sm:inline">Dashboard</span>
          </Link>
          <Link 
            to="/clientes" 
            className={`flex items-center gap-2 text-sm transition-colors ${location.pathname === '/clientes' ? 'text-brand-green font-bold' : 'text-white/70 hover:text-brand-green'}`}
          >
            <Users size={18} />
            <span className="hidden sm:inline">Meus Clientes</span>
          </Link>
          <div className="hidden xs:flex items-center gap-1 text-[10px] text-brand-green bg-brand-green/10 px-3 py-1 rounded-full border border-brand-green/20 font-bold uppercase tracking-wider">
            <ShieldCheck size={14} />
            <span>Gestor</span>
          </div>
        </div>
      ) : (
        <div className="flex items-center gap-2 text-[10px] text-brand-blue bg-brand-blue/10 px-4 py-2 rounded-full border border-brand-blue/20">
          <Lock size={14} />
          <span className="font-bold uppercase tracking-[0.15em]">Portal do Cliente Seguro</span>
        </div>
      )}
    </div>
  </div>
</nav>
);
};
export default Navbar;
COMPONENTS - SIGNATURECANVAS
import React, { useRef, useEffect, useState } from 'react';
import { RotateCcw } from 'lucide-react';
interface Props {
onSave: (dataUrl: string) => void;
onClear: () => void;
}
const SignatureCanvas: React.FC<Props> = ({ onSave, onClear }) => {
const canvasRef = useRef<HTMLCanvasElement>(null);
const [isDrawing, setIsDrawing] = useState(false);
useEffect(() => {
const canvas = canvasRef.current;
if (!canvas) return;
code
Code
const ctx = canvas.getContext('2d');
if (!ctx) return;

const updateSize = () => {
  const rect = canvas.getBoundingClientRect();
  canvas.width = rect.width;
  canvas.height = rect.height;
  ctx.lineWidth = 2.5;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';
  ctx.strokeStyle = '#0A1E29'; // Cor da tinta (preto/azul escuro da marca)
};

updateSize();
window.addEventListener('resize', updateSize);
return () => window.removeEventListener('resize', updateSize);
}, []);
const getPos = (e: React.MouseEvent | React.TouchEvent) => {
const canvas = canvasRef.current;
if (!canvas) return { x: 0, y: 0 };
const rect = canvas.getBoundingClientRect();
code
Code
// Suporte para touch e mouse
const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

return {
  x: clientX - rect.left,
  y: clientY - rect.top,
};
};
const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
// Previne scroll ao assinar no mobile
if ('touches' in e) {
// e.preventDefault(); // Removido para evitar erros em alguns browsers, usando touch-none no CSS
}
code
Code
setIsDrawing(true);
const pos = getPos(e);
const ctx = canvasRef.current?.getContext('2d');
if (ctx) {
  ctx.beginPath();
  ctx.moveTo(pos.x, pos.y);
}
};
const draw = (e: React.MouseEvent | React.TouchEvent) => {
if (!isDrawing) return;
const pos = getPos(e);
const ctx = canvasRef.current?.getContext('2d');
if (ctx) {
ctx.lineTo(pos.x, pos.y);
ctx.stroke();
}
};
const endDrawing = () => {
if (!isDrawing) return;
setIsDrawing(false);
const canvas = canvasRef.current;
if (canvas) {
onSave(canvas.toDataURL());
}
};
const clear = () => {
const canvas = canvasRef.current;
if (canvas) {
const ctx = canvas.getContext('2d');
ctx?.clearRect(0, 0, canvas.width, canvas.height);
onClear();
}
};
return (
<div className="relative">
<div className="flex justify-between items-center mb-2">
<label className="text-[10px] font-bold uppercase tracking-widest text-brand-green">Assine no campo abaixo:</label>
<button
type="button"
onClick={clear}
className="text-[10px] flex items-center gap-1 text-white/40 hover:text-white transition-colors uppercase font-bold"
>
<RotateCcw size={12} /> Limpar
</button>
</div>
<div className="bg-white rounded-xl overflow-hidden shadow-inner border-2 border-brand-green/30">
<canvas
ref={canvasRef}
onMouseDown={startDrawing}
onMouseMove={draw}
onMouseUp={endDrawing}
onMouseLeave={endDrawing}
onTouchStart={startDrawing}
onTouchMove={draw}
onTouchEnd={endDrawing}
className="w-full h-40 touch-none cursor-crosshair"
/>
</div>
<p className="mt-2 text-[9px] text-white/30 text-center uppercase tracking-tighter">Sua assinatura será espelhada no contrato automaticamente</p>
</div>
);
};
export default SignatureCanvas;
PAGES - ADMINDASHBOARD
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { webhookService } from '../services/webhookService';
import { Contract, PlanType, AdminFormData, Region, Clause } from '../types';
import ContractPreview from '../components/ContractPreview';
import { SERVICES, CONTRACT_TEMPLATE, PERSONALIZED_SERVICES, DEFAULT_INSTRUCTIONS_STANDARD, DEFAULT_INSTRUCTIONS_PERSONALIZED } from '../constants';
import { generateUUID, generateShortId } from '../utils';
import { Plus, CheckCircle2, Clock, Copy, Check, X, ChevronRight, LayoutGrid, Sparkles, PenTool, DollarSign, Wallet, ExternalLink, AlertTriangle, Building2, UserCircle, ScrollText, MessageSquareQuote } from 'lucide-react';
const PERSONALIZED_TAB = 'Contrato Personalizado';
const AdminDashboard: React.FC = () => {
const [contracts, setContracts] = useState<Contract[]>([]);
const [selectedService, setSelectedService] = useState<string>(SERVICES[1]);
const [showModal, setShowModal] = useState(false);
const [showSuccess, setShowSuccess] = useState<string | null>(null);
const [isSyncing, setIsSyncing] = useState(false);
const [isLoading, setIsLoading] = useState(true);
const [formData, setFormData] = useState<AdminFormData>({
serviceType: SERVICES[1],
providerName: 'PATRICIA GUIMARÃES',
providerBrand: 'EASY BYZ CREATOR',
providerAddress: 'Santa Ana, CA - EUA',
adminName: '',
companyName: '',
planType: PlanType.MONTHLY,
planValue: '23.90',
annualValue: '239.00',
setupFee: '49.00',
paymentKey: '',
zelleKey: '',
venmoKey: '',
paymentLink: '',
clauses: JSON.parse(JSON.stringify(CONTRACT_TEMPLATE.clauses)),
hiddenFields: [],
activationInstructions: DEFAULT_INSTRUCTIONS_STANDARD
});
useEffect(() => {
const fetchContracts = async () => {
setIsLoading(true);
const data = await storageService.getAllContracts();
setContracts(data);
setIsLoading(false);
};
fetchContracts();
}, []);
const filteredContracts = contracts.filter(c => {
if (selectedService === PERSONALIZED_TAB) {
return PERSONALIZED_SERVICES.includes(c.serviceType) || (!SERVICES.includes(c.serviceType));
}
return c.serviceType === selectedService;
});
const handleOpenModal = () => {
const serviceLower = selectedService.toLowerCase();
const isPersonalized = selectedService === PERSONALIZED_TAB;
const isBR = serviceLower.includes(' br');
const isAgenda = serviceLower.includes('agenda');
code
Code
let defaultPlanValue = '23.90';
let defaultAnnualValue = '239.00';
let defaultSetupFee = '49.00';
let initialServiceType = selectedService;
let defaultInstructions = DEFAULT_INSTRUCTIONS_STANDARD;

if (isPersonalized) {
  defaultPlanValue = ''; defaultAnnualValue = ''; defaultSetupFee = '';
  initialServiceType = PERSONALIZED_SERVICES[0];
  defaultInstructions = DEFAULT_INSTRUCTIONS_PERSONALIZED;
} else if (isBR) {
  if (isAgenda) {
    defaultPlanValue = '54,90'; defaultAnnualValue = '545,00'; defaultSetupFee = '145,00';
  } else {
    defaultPlanValue = '119,50'; defaultAnnualValue = '1195,00'; defaultSetupFee = '145,00';
  }
} else if (isAgenda) {
  defaultPlanValue = '10.90'; defaultAnnualValue = '109.00'; defaultSetupFee = '29.00';
}

setFormData({
  ...formData,
  serviceType: initialServiceType,
  adminName: '', 
  companyName: '', 
  paymentKey: '', 
  zelleKey: '', 
  venmoKey: '', 
  paymentLink: '',
  planValue: defaultPlanValue, 
  annualValue: defaultAnnualValue, 
  setupFee: defaultSetupFee,
  clauses: JSON.parse(JSON.stringify(CONTRACT_TEMPLATE.clauses)), 
  hiddenFields: [], 
  activationInstructions: defaultInstructions
});
setShowModal(true);
};
const handleClauseChange = (index: number, content: string) => {
const newClauses = [...formData.clauses];
newClauses[index].content = content;
setFormData({ ...formData, clauses: newClauses });
};
const generateClientLink = (contract: Contract) => {
if (!contract.shortId || contract.shortId === 'undefined') return "";
return ${window.location.origin}/#/c/${contract.shortId};
};
const handleCreate = async (e: React.FormEvent) => {
e.preventDefault();
setIsSyncing(true);
code
Code
const newId = generateUUID();
const newShortId = generateShortId();
const region: Region = formData.serviceType.toLowerCase().includes(' br') ? 'BR' : 'USA';

const newContract: Contract = {
  ...formData,
  id: newId,
  shortId: newShortId,
  region,
  status: 'pending',
  createdAt: new Date().toLocaleString('pt-BR'),
};

try {
  await storageService.saveContract(newContract);
  await webhookService.sendToSheets(newContract);

  setContracts(prev => [newContract, ...prev]);
  setShowModal(false);
  setShowSuccess(newId);
  window.scrollTo({ top: 0, behavior: 'smooth' });
} catch (error) {
  alert("Erro ao salvar no banco de dados. Verifique sua conexão.");
} finally {
  setIsSyncing(false);
}
};
const copyLink = (contract: Contract) => {
const link = generateClientLink(contract);
if (!link) {
alert('Erro: ID inválido.');
return;
}
navigator.clipboard.writeText(link);
alert('Link curto copiado!');
};
return (
<div className="flex min-h-screen bg-brand-dark text-white">
<aside className="w-64 border-r border-white/10 hidden lg:flex flex-col sticky top-0 h-screen bg-brand-dark/50 backdrop-blur-xl">
<div className="p-6 flex-grow">
<div className="flex items-center gap-2 mb-8 px-2 text-white/40 uppercase tracking-widest text-[10px] font-bold">
<LayoutGrid size={16} className="text-brand-green" /> Serviços Easy
</div>
<nav className="space-y-1">
{SERVICES.map((service) => (
<button key={service} onClick={() => setSelectedService(service)} className={w-full text-left px-4 py-3 rounded-xl transition-all flex items-center justify-between group ${selectedService === service ? 'bg-brand-green/10 text-brand-green font-bold' : 'text-white/50 hover:bg-white/5'}}>
<span className="capitalize">{service}</span>
{selectedService === service && <ChevronRight size={14} />}
</button>
))}
<div className="pt-4 mt-4 border-t border-white/5">
<button onClick={() => setSelectedService(PERSONALIZED_TAB)} className={w-full text-left px-4 py-3 rounded-xl transition-all flex items-center justify-between group ${selectedService === PERSONALIZED_TAB ? 'bg-brand-blue/10 text-brand-blue font-bold' : 'text-white/30 hover:bg-white/5'}}>
<span className="flex items-center gap-2"><Sparkles size={16} /> Personalizado</span>
{selectedService === PERSONALIZED_TAB && <ChevronRight size={14} />}
</button>
</div>
</nav>
</div>
</aside>
code
Code
<main className="flex-grow p-4 md:p-8">
    {showSuccess && (
      <div className="mb-6 bg-brand-green/20 border border-brand-green/30 p-4 rounded-2xl flex flex-col sm:flex-row items-center justify-between gap-4 animate-in fade-in slide-in-from-top-4">
        <div className="flex items-center gap-3">
          <div className="bg-brand-green text-brand-dark p-2 rounded-full"><Check size={20} /></div>
          <div>
            <p className="font-bold text-brand-green uppercase tracking-wide text-xs">Contrato Gerado!</p>
            <p className="text-[10px] text-white/60">O link curto está pronto.</p>
          </div>
        </div>
        <button 
          onClick={() => {
            const c = contracts.find(c => c.id === showSuccess);
            if (c) copyLink(c);
          }}
          className="w-full sm:w-auto bg-brand-green text-brand-dark px-6 py-2 rounded-lg font-bold text-xs flex items-center justify-center gap-2 hover:brightness-110 shadow-lg shadow-brand-green/20"
        >
          <Copy size={16} /> Copiar Link Curto
        </button>
      </div>
    )}

    <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
      <div>
        <h1 className="text-2xl md:text-3xl font-bold capitalize">{selectedService}</h1>
        <p className="text-white/40 text-sm">Controle de registros e assinaturas.</p>
      </div>
      <button onClick={handleOpenModal} className="font-bold px-6 py-4 rounded-xl bg-brand-green text-brand-dark shadow-xl shadow-brand-green/20 flex items-center justify-center gap-2 hover:scale-105 transition-transform">
        <Plus size={20} /> Novo Contrato
      </button>
    </div>

    <div className="grid grid-cols-1 gap-3">
      {isLoading ? (
        <div className="flex flex-col items-center justify-center py-20">
          <Clock className="animate-spin text-brand-green mb-4" size={32} />
          <p className="text-white/40 text-xs font-bold uppercase">Carregando Nuvem...</p>
        </div>
      ) : filteredContracts.length === 0 ? (
        <div className="text-center py-20 bg-white/5 rounded-2xl border border-white/10">
          <Clock size={48} className="mx-auto mb-4 text-white/20" />
          <p className="text-white/40">Nenhum contrato aqui.</p>
        </div>
      ) : (
        filteredContracts.map(contract => (
          <div key={contract.id} className="bg-white/5 border border-white/10 rounded-2xl p-4 flex flex-col sm:flex-row items-center justify-between gap-4 group hover:bg-white/10 transition-all">
            <div className="flex items-center gap-4 w-full sm:w-auto">
              <div className={`w-10 h-10 rounded-full flex items-center justify-center ${contract.status === 'signed' ? 'bg-brand-green/20 text-brand-green' : 'bg-brand-blue/20 text-brand-blue'}`}>
