export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { webhookService } from '../services/webhookService';
import { Contract, PaymentStatus, DeliveryStatus, Region, PlanType } from '../types';
import { Search, User, Calendar, ArrowRight, UserCheck, Globe, ExternalLink, Settings2, X, AlertCircle, Clock, Trash2, Truck, CheckCircle2, RefreshCw, ShieldAlert } from 'lucide-react';
import { isToday, isThisWeek, isThisMonth, addBusinessDays, getDaysRemaining, getPlanExpirationDate, getPlanDaysRemaining } from '../utils';
import { PERSONALIZED_SERVICES } from '../constants';

const ClientsList: React.FC = () => {
  const navigate = useNavigate();
  const [searchTerm, setSearchTerm] = useState('');
  const [clients, setClients] = useState<Contract[]>([]);
  const [regionFilter, setRegionFilter] = useState<'all' | Region>('all');
  const [financeFilter, setFinanceFilter] = useState<'all' | 'today' | 'week' | 'month'>('all');
  const [deliveryView, setDeliveryView] = useState(false);
  const [expiryView, setExpiryView] = useState(false);
  const [managingClient, setManagingClient] = useState<Contract | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    loadClients();
  }, []);

  const loadClients = async () => {
    setIsLoading(true);
    const all = await storageService.getAllContracts();
    const signed = all.filter(c => c.status === 'signed');
    setClients(signed);
    setIsLoading(false);
  };

  const handleUpdateClient = async (updated: Contract) => {
    setIsSyncing(true);
    try {
      await storageService.saveContract(updated);
      setClients(prev => prev.map(c => c.id === updated.id ? updated : c));
      await webhookService.sendToSheets(updated);
      setManagingClient(null);
    } catch (error) {
      alert("Erro ao sincronizar com a Nuvem.");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleDeleteClient = async (id: string, name: string) => {
    if (window.confirm(`Excluir o cliente "${name}" da Nuvem?`)) {
      await storageService.deleteContract(id);
      setClients(prev => prev.filter(c => c.id !== id));
    }
  };

  const toggleReady = async (client: Contract) => {
    const newStatus: DeliveryStatus = client.deliveryStatus === 'delivered' ? 'pending' : 'delivered';
    const updated = { ...client, deliveryStatus: newStatus };
    setClients(prev => prev.map(c => c.id === updated.id ? updated : c));
    await storageService.saveContract(updated);
    webhookService.sendToSheets(updated);
  };

  const filteredClients = clients.filter(c => {
    const name = c.clientData?.fullName || '';
    const matchesSearch =
      name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (c.clientData?.cpf || '').includes(searchTerm) ||
      c.companyName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.serviceType.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesRegion = regionFilter === 'all' || c.region === regionFilter;

    let matchesFinance = true;
    if (financeFilter === 'today') matchesFinance = isToday(c.nextDueDate);
    if (financeFilter === 'week') matchesFinance = isThisWeek(c.nextDueDate);
    if (financeFilter === 'month') matchesFinance = isThisMonth(c.nextDueDate);

    if (deliveryView && c.deliveryStatus === 'delivered' && !searchTerm) return false;

    return matchesSearch && matchesRegion && matchesFinance;
  });

  const displayedClients = expiryView
    ? [...filteredClients].sort((a, b) => getPlanDaysRemaining(a.signedAt) - getPlanDaysRemaining(b.signedAt))
    : filteredClients;

  const getStatusLabel = (status?: PaymentStatus) => {
    switch (status) {
      case 'paid': return { label: 'Em Dia', color: 'text-brand-green bg-brand-green/10' };
      case 'overdue': return { label: 'Atrasado', color: 'text-red-400 bg-red-400/10' };
      case 'inactive': return { label: 'Inativo', color: 'text-white/40 bg-white/5' };
      default: return { label: 'Aguardando', color: 'text-yellow-400 bg-yellow-400/10' };
    }
  };

  const getDeliveryInfo = (client: Contract) => {
    if (!client.signedAt) return { deadline: '---', remaining: 0 };
    const isPersonalized = PERSONALIZED_SERVICES.includes(client.serviceType);
    const days = isPersonalized ? 30 : 15;
    const deadline = addBusinessDays(client.signedAt, days);
    const remaining = getDaysRemaining(deadline);
    return { deadline, remaining };
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <div>
          <h1 className="text-3xl font-bold text-white flex items-center gap-3">
            <UserCheck className="text-brand-green" /> Meus Clientes
          </h1>
          <p className="text-white/60">Gestão operacional na nuvem.</p>
        </div>
        <div className="flex flex-wrap gap-2 items-center">
          <button 
            onClick={() => { setDeliveryView(!deliveryView); setExpiryView(false); }}
            className={`px-4 py-2 rounded-xl text-xs font-bold flex items-center gap-2 border transition-all ${deliveryView ? 'bg-brand-green border-brand-green text-brand-dark shadow-lg shadow-brand-green/20' : 'bg-white/5 border-white/10 text-white/40 hover:text-white'}`}
          >
            <Truck size={16} /> Fila de Entrega
          </button>
          <button 
            onClick={() => { setExpiryView(!expiryView); setDeliveryView(false); }}
            className={`px-4 py-2 rounded-xl text-xs font-bold flex items-center gap-2 border transition-all ${expiryView ? 'bg-brand-blue border-brand-blue text-brand-dark shadow-lg shadow-brand-blue/20' : 'bg-white/5 border-white/10 text-white/40 hover:text-white'}`}
          >
            <ShieldAlert size={16} /> Planos a vencer
          </button>
          <div className="h-8 w-px bg-white/10 mx-2 hidden md:block"></div>
          <button onClick={() => setRegionFilter(regionFilter === 'USA' ? 'all' : 'USA')} className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${regionFilter === 'USA' ? 'bg-brand-blue border-brand-blue text-brand-dark' : 'bg-white/5 border-white/10 text-white/40'}`}>🇺🇸 USA</button>
          <button onClick={() => setRegionFilter(regionFilter === 'BR' ? 'all' : 'BR')} className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${regionFilter === 'BR' ? 'bg-brand-green border-brand-green text-brand-dark' : 'bg-white/5 border-white/10 text-white/40'}`}>🇧🇷 BR</button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-8">
        <div className="lg:col-span-2 relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-white/30" size={20} />
          <input 
            type="text"
            placeholder="Buscar por nome, empresa..."
            className="w-full bg-white/5 border border-white/10 rounded-2xl pl-12 pr-4 py-4 focus:outline-none focus:border-brand-green text-white"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="grid grid-cols-3 gap-3 lg:col-span-3">
          <button onClick={() => setFinanceFilter(financeFilter === 'today' ? 'all' : 'today')} className={`flex flex-col items-center justify-center p-3 rounded-2xl border ${financeFilter === 'today' ? 'bg-brand-blue border-brand-blue text-brand-dark' : 'bg-white/5 border-white/10 text-white/40'}`}><AlertCircle size={18} /><span className="text-[9px] font-bold uppercase mt-1">Hoje</span></button>
          <button onClick={() => setFinanceFilter(financeFilter === 'week' ? 'all' : 'week')} className={`flex flex-col items-center justify-center p-3 rounded-2xl border ${financeFilter === 'week' ? 'bg-brand-green border-brand-green text-brand-dark' : 'bg-white/5 border-white/10 text-white/40'}`}><Calendar size={18} /><span className="text-[9px] font-bold uppercase mt-1">Semana</span></button>
          <button onClick={() => setFinanceFilter(financeFilter === 'month' ? 'all' : 'month')} className={`flex flex-col items-center justify-center p-3 rounded-2xl border ${financeFilter === 'month' ? 'bg-brand-blue border-brand-blue text-brand-dark' : 'bg-white/5 border-white/10 text-white/40'}`}><Clock size={18} /><span className="text-[9px] font-bold uppercase mt-1">Mês</span></button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {isLoading ? (
          <div className="col-span-full flex flex-col items-center justify-center py-20">
            <Clock className="animate-spin text-brand-green mb-4" size={32} />
            <p className="text-white/40 text-xs font-bold uppercase">Carregando Assinaturas...</p>
          </div>
        ) : displayedClients.length === 0 ? (
           <div className="col-span-full text-center py-20 bg-white/5 rounded-2xl border border-white/10">
            <User className="mx-auto mb-4 text-white/10" size={48} />
            <p className="text-white/40">Nenhum cliente assinado encontrado.</p>
          </div>
        ) : displayedClients.map(client => {
          const statusInfo = getStatusLabel(client.paymentStatus);
          const isDelivered = client.deliveryStatus === 'delivered';
          const expirationDate = getPlanExpirationDate(client.signedAt);
          const deliveryInfo = getDeliveryInfo(client);

          return (
            <div key={client.id} className="bg-white/5 border border-white/10 rounded-2xl p-6 hover:bg-white/10 transition-all group flex flex-col relative overflow-hidden">
              <div className="absolute top-0 right-0 p-3 flex gap-2">
                <span className={`text-[9px] font-bold px-2 py-1 rounded uppercase tracking-wider border ${statusInfo.color}`}>{statusInfo.label}</span>
                <button onClick={() => handleDeleteClient(client.id, client.clientData?.fullName || client.adminName)} className="p-1.5 text-white/20 hover:text-red-400"><Trash2 size={16} /></button>
              </div>

              <div className="flex items-center gap-4 mb-4">
                <div className="w-14 h-14 rounded-full flex items-center justify-center shrink-0 bg-brand-green/20 text-brand-green"><User size={28} /></div>
                <div className="overflow-hidden text-left">
                  <h3 className="font-bold text-lg text-white truncate">{client.clientData?.fullName}</h3>
                  <p className="text-sm text-white/40 truncate uppercase text-[10px] tracking-widest">{client.companyName}</p>
                </div>
              </div>

              <div className="bg-white/5 rounded-xl p-4 mb-6 space-y-3 flex-grow text-xs">
                <div className="flex items-center justify-between">
                  <span className="text-brand-blue font-bold uppercase">{client.serviceType}</span>
                  {isDelivered ? (
                    <span className="text-[10px] text-brand-green font-bold flex items-center gap-1"><CheckCircle2 size={12} /> ENTREGUE</span>
                  ) : deliveryView ? (
                    <span className="text-[10px] text-yellow-400 font-bold flex items-center gap-1"><Clock size={12} /> EM PRODUÇÃO</span>
                  ) : null}
                </div>

                <div className="grid grid-cols-2 gap-4 pt-2 border-t border-white/5 text-left">
                  <div>
                    <p className="text-white/30 uppercase font-bold text-[9px]">Valor Contratado</p>
                    <p className="text-white/70 font-medium">{client.region === 'BR' ? 'R$' : '$'}{client.planType === PlanType.ANNUAL ? client.annualValue : client.planValue}</p>
                  </div>

                  <div className="text-right">
                    {deliveryView ? (
                      <>
                        <p className="text-brand-green uppercase font-bold text-[9px]">Entrega Limite</p>
                        <p className="text-brand-green font-bold text-[13px]">{deliveryInfo?.deadline}</p>
                      </>
                    ) : expiryView ? (
                      <>
                        <p className="text-brand-blue uppercase font-bold text-[9px]">Fim do Contrato</p>
                        <p className="text-brand-blue font-bold text-[13px]">{expirationDate}</p>
                      </>
                    ) : (
                      <>
                        <p className="text-white/30 uppercase font-bold text-[9px]">Vencimento</p>
                        <p className="text-white/70 font-bold text-[13px]">{client.nextDueDate ? new Date(client.nextDueDate).toLocaleDateString('pt-BR') : 'A definir'}</p>
                      </>
                    )}
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-3 gap-2">
                <button onClick={() => toggleReady(client)} className={`flex items-center justify-center gap-2 py-3 rounded-xl font-bold text-[10px] uppercase transition-all ${isDelivered ? 'bg-brand-green text-brand-dark' : 'bg-white/5 text-brand-green border border-brand-green/20 hover:bg-brand-green/10'}`}><CheckCircle2 size={14} /> {isDelivered ? 'Pronto' : 'Marcar'}</button>
                <button onClick={() => setManagingClient(client)} className="flex items-center justify-center gap-2 bg-white/5 text-white/60 border border-white/10 py-3 rounded-xl font-bold text-[10px] uppercase hover:bg-white/10 transition-all"><Settings2 size={14} /> Gerenciar</button>
                <button onClick={() => navigate(`/contrato/${client.id}`, { state: { fromAdmin: true } })} className="flex items-center justify-center gap-2 bg-brand-green/10 text-brand-green border border-brand-green/10 py-3 rounded-xl font-bold text-[10px] uppercase hover:bg-brand-green/20 transition-all">Ficha <ArrowRight size={14} /></button>
              </div>
            </div>
          );
        })}
      </div>

      {managingClient && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-brand-dark border border-white/10 rounded-3xl w-full max-w-md shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-6 border-b border-white/10 flex items-center justify-between bg-white/5">
              <div className="flex items-center gap-3">
                <Settings2 className="text-brand-green" size={20} />
                <h2 className="font-bold text-sm uppercase tracking-widest text-white">Painel de Gestão</h2>
              </div>
              <button onClick={() => setManagingClient(null)} className="text-white/20 hover:text-white"><X size={24} /></button>
            </div>

            <div className="p-6 space-y-5 max-h-[80vh] overflow-y-auto custom-scrollbar">
              <div className="bg-white/5 border border-white/10 rounded-2xl p-4 space-y-4">
                <div className="flex items-center justify-between">
                   <h4 className="text-[10px] font-bold text-brand-green uppercase tracking-widest flex items-center gap-2">
                    <Truck size={14} /> Produção / Prazo
                  </h4>
                  <span className="text-[9px] text-white/30 uppercase font-bold">Expira: {getPlanExpirationDate(managingClient.signedAt)}</span>
                </div>
                <div>
                  <label className="block text-[9px] font-bold uppercase text-white/40 mb-1">Status da Entrega</label>
                  <select className="w-full bg-brand-dark border border-white/10 rounded-xl px-3 py-3 text-sm font-bold text-white outline-none" value={managingClient.deliveryStatus || 'pending'} onChange={(e) => setManagingClient({...managingClient, deliveryStatus: e.target.value as DeliveryStatus})}>
                    <option value="pending">Produção Pendente</option>
                    <option value="delivered">Sistema Entregue (Pronto)</option>
                  </select>
                </div>
              </div>

              <div className="space-y-4">
                <div>
                  <label className="block text-[9px] font-bold uppercase text-white/40 mb-1">Link do Sistema Finalizado</label>
                  <input type="text" className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-sm text-white outline-none" placeholder="https://..." value={managingClient.finalSystemLink || ''} onChange={(e) => setManagingClient({...managingClient, finalSystemLink: e.target.value})} />
                </div>

                <div className="grid grid-cols-2 gap-4 text-left">
                  <div>
                    <label className="block text-[9px] font-bold uppercase text-white/40 mb-1">Status Financeiro</label>
                    <select className="w-full bg-brand-dark border border-white/10 rounded-xl p-3 text-sm text-white" value={managingClient.paymentStatus || 'awaiting_setup'} onChange={(e) => setManagingClient({...managingClient, paymentStatus: e.target.value as PaymentStatus})}>
                      <option value="awaiting_setup">Aguardando Setup</option>
                      <option value="paid">Em Dia</option>
                      <option value="overdue">Atrasado</option>
                      <option value="inactive">Inativo</option>
                    </select>
                  </div>
                  <div>
                    <label className="block text-[9px] font-bold uppercase text-white/40 mb-1">Próx. Vencimento</label>
                    <input type="date" className="w-full bg-brand-dark border border-white/10 rounded-xl p-3 text-sm text-white" value={managingClient.nextDueDate || ''} onChange={(e) => setManagingClient({...managingClient, nextDueDate: e.target.value})} />
                  </div>
                </div>
              </div>

              <div className="pt-4 flex gap-3">
                <button onClick={() => setManagingClient(null)} className="flex-1 py-4 text-[10px] font-bold uppercase text-white/40">Cancelar</button>
                <button onClick={() => handleUpdateClient(managingClient)} disabled={isSyncing} className="flex-2 bg-brand-green text-brand-dark px-8 py-4 rounded-2xl text-[10px] font-bold uppercase flex items-center justify-center gap-2">
                  {isSyncing ? <RefreshCw size={14} className="animate-spin" /> : 'Salvar Alterações'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ClientsList;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { webhookService } from '../services/webhookService';
import { Contract, ClientData } from '../types';
import { formatCPF, formatWhatsApp, validateCPF, validateWhatsApp, getClientIP, getClientLocation } from '../utils';
import ContractPreview from '../components/ContractPreview';
import SignatureCanvas from '../components/SignatureCanvas';
import { BRAND } from '../constants';
import { User, Phone, MapPin, Mail, AlertCircle, Clock, ShieldCheck, FileText } from 'lucide-react';

const ClientSign: React.FC = () => {
  const { id, shortId } = useParams<{ id?: string; shortId?: string }>();
  const navigate = useNavigate();
  const location = useLocation();
  const [contract, setContract] = useState<Contract | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSearching, setIsSearching] = useState(true);

  const [clientData, setClientData] = useState<ClientData>({
    fullName: '',
    email: '',
    cpf: '',
    birthDate: '',
    whatsapp: '',
    address: ''
  });
  const [signature, setSignature] = useState<string>('');

  useEffect(() => {
    const fetchContract = async () => {
      setIsSearching(true);
      setError(null);
      try {
        let c: Contract | undefined;
        if (shortId) {
          c = await storageService.getContractByShortId(shortId);
        }
        if (!c && id) {
          c = await storageService.getContractById(id);
        }
        if (c) {
          setContract(c);
          if (c.status === 'signed') navigate(`/contrato/${c.id}`);
        } else {
          setError('Este contrato não foi encontrado na nuvem ou o link expirou.');
        }
      } catch (err) {
        setError('Ocorreu um erro ao conectar com o servidor. Tente novamente.');
      } finally {
        setIsSearching(false);
      }
    };
    fetchContract();
  }, [id, shortId, navigate]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (clientData.fullName.length < 5) return setError('Digite seu nome completo.');
    if (!validateCPF(clientData.cpf)) return setError('CPF inválido.');
    if (!validateWhatsApp(clientData.whatsapp)) return setError('WhatsApp inválido.');
    if (!signature) return setError('A assinatura é obrigatória.');

    setIsSubmitting(true);
    try {
      const ip = await getClientIP();
      const loc = await getClientLocation();

      const updatedContract: Contract = {
        ...contract!,
        status: 'signed',
        signedAt: new Date().toLocaleString('pt-BR'),
        clientData,
        signatureImage: signature,
        metadata: {
          ip,
          location: loc,
          userAgent: navigator.userAgent
        }
      };

      await storageService.saveContract(updatedContract);
      await webhookService.sendToSheets(updatedContract);

      navigate(`/contrato/${updatedContract.id}`, { state: { autoPrint: true } });
    } catch (e) {
      setError('Erro ao processar assinatura na nuvem. Tente novamente.');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (error) return (
    <div className="flex flex-col items-center justify-center min-h-[70vh] text-center px-6">
      <AlertCircle size={60} className="text-red-400 mb-4" />
      <h2 className="text-xl font-bold mb-2">Acesso Negado</h2>
      <p className="text-white/40 mb-6 max-w-sm">{error}</p>
      <button onClick={() => window.location.reload()} className="text-brand-green border border-brand-green/20 bg-brand-green/10 px-6 py-3 rounded-xl font-bold uppercase text-[10px]">Tentar Novamente</button>
    </div>
  );

  if (isSearching) return (
    <div className="flex flex-col items-center justify-center min-h-[70vh]">
      <Clock className="animate-spin text-brand-green mb-4" size={40} />
      <p className="text-white/40 font-bold uppercase tracking-widest text-[10px]">Buscando Contrato na Nuvem...</p>
    </div>
  );

  if (!contract) return null;

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="flex flex-col lg:flex-row gap-8 items-start">
        <div className="lg:w-3/5 w-full space-y-4">
          <div className="flex items-center gap-2 text-brand-green font-bold uppercase tracking-widest text-[10px] mb-2">
            <FileText size={16} /> Verifique os termos abaixo:
          </div>
          <div className="bg-white rounded-2xl shadow-2xl overflow-hidden border border-white/10 ring-1 ring-white/5">
            <div className="max-h-[75vh] overflow-y-auto custom-scrollbar">
              <ContractPreview
                {...contract}
                clientData={clientData}
                signature={signature}
              />
            </div>
          </div>
        </div>

        <div className="lg:w-2/5 w-full lg:sticky lg:top-24">
          <div className="bg-white/5 border border-white/10 rounded-3xl p-6 md:p-8 backdrop-blur-xl shadow-2xl space-y-8">
            <div className="text-center">
              <img src={BRAND.logo} alt="Logo" className="h-14 mx-auto mb-4" />
              <h1 className="text-2xl font-bold text-white">Assinatura Digital</h1>
              <p className="text-brand-green text-[10px] font-bold uppercase tracking-[0.2em] mt-2">Segura e Blindada</p>
            </div>

            <form onSubmit={handleSubmit} className="space-y-5">
              <div className="space-y-4">
                <div className="relative">
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" size={16} />
                  <input type="text" required placeholder="Nome Completo" className="w-full bg-white/5 border border-white/10 rounded-2xl pl-12 pr-4 py-4 outline-none focus:border-brand-green text-sm text-white" value={clientData.fullName} onChange={e => setClientData({...clientData, fullName: e.target.value})} />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <input type="text" required placeholder="CPF (11 dígitos)" className="w-full bg-white/5 border border-white/10 rounded-2xl px-4 py-4 outline-none focus:border-brand-green text-sm text-white" value={clientData.cpf} onChange={e => setClientData({...clientData, cpf: formatCPF(e.target.value)})} />
                  <input type="date" required className="w-full bg-white/5 border border-white/10 rounded-2xl px-4 py-4 outline-none focus:border-brand-green text-sm text-white" value={clientData.birthDate} onChange={e => setClientData({...clientData, birthDate: e.target.value})} />
                </div>

                <div className="relative">
                  <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" size={16} />
                  <input type="text" required placeholder="WhatsApp" className="w-full bg-white/5 border border-white/10 rounded-2xl pl-12 pr-4 py-4 outline-none focus:border-brand-green text-sm text-white" value={clientData.whatsapp} onChange={e => setClientData({...clientData, whatsapp: formatWhatsApp(e.target.value, contract.region)})} />
                </div>

                <div className="relative">
                  <MapPin className="absolute left-4 top-4 text-white/20" size={16} />
                  <textarea required rows={2} placeholder="Endereço Completo" className="w-full bg-white/5 border border-white/10 rounded-2xl pl-12 pr-4 py-4 outline-none focus:border-brand-green text-sm text-white resize-none" value={clientData.address} onChange={e => setClientData({...clientData, address: e.target.value})} />
                </div>

                <div className="relative">
                  <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" size={16} />
                  <input type="email" required placeholder="E-mail para receber cópia" className="w-full bg-white/5 border border-white/10 rounded-2xl pl-12 pr-4 py-4 outline-none focus:border-brand-green text-sm text-white" value={clientData.email} onChange={e => setClientData({...clientData, email: e.target.value})} />
                </div>
              </div>

              <div className="pt-4 border-t border-white/10 text-left">
                <SignatureCanvas onSave={setSignature} onClear={() => setSignature('')} />
              </div>

              {error && (
                <div className="p-4 bg-red-500/10 border border-red-500/20 text-red-400 text-[10px] rounded-2xl flex items-center gap-2 font-bold uppercase">
                  <AlertCircle size={16} /> {error}
                </div>
              )}

              <button type="submit" disabled={isSubmitting} className="w-full bg-brand-green text-brand-dark font-black py-5 rounded-2xl shadow-xl shadow-brand-green/20 hover:brightness-110 active:scale-95 transition-all uppercase tracking-[0.2em] text-[10px] flex items-center justify-center gap-2">
                {isSubmitting ? (
                  <><Clock className="animate-spin" size={18} /> Validando...</>
                ) : (
                  <><ShieldCheck size={18} /> Finalizar e Assinar</>
                )}
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ClientSign;

import React, { useEffect, useState } from 'react';
import { useParams, Link, useLocation, useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { Contract, PaymentStatus } from '../types';
import ContractPreview from '../components/ContractPreview';
import { ChevronLeft, ShieldCheck, Globe, Calendar, Download, AlertCircle, Trash2, UserX, UserCheck, Clock } from 'lucide-react';

const ContractDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const location = useLocation();
  const navigate = useNavigate();
  const [contract, setContract] = useState<Contract | null>(null);
  const [isPreparing, setIsPreparing] = useState(false);
  const [showManualTrigger, setShowManualTrigger] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  const isAdmin = location.state?.fromAdmin || false;

  useEffect(() => {
    const fetchContract = async () => {
      if (id) {
        setIsLoading(true);
        const data = await storageService.getContractById(id);
        setContract(data || null);
        setIsLoading(false);
      }
    };
    fetchContract();
  }, [id]);

  useEffect(() => {
    if (contract && location.state?.autoPrint) {
      setIsPreparing(true);
      const timer = setTimeout(() => {
        setIsPreparing(false);
        try {
          window.print();
          window.history.replaceState({}, document.title);
        } catch (e) {
          setShowManualTrigger(true);
        }
      }, 2000);
      return () => clearTimeout(timer);
    }
  }, [contract, location.state]);

  const handleManualPrint = () => {
    try {
      window.print();
    } catch (e) {
      alert("Para baixar o PDF, use a função Imprimir do seu navegador e selecione 'Salvar como PDF'.");
    }
  };

  const handleDelete = async () => {
    if (!contract) return;
    if (window.confirm(`Excluir permanentemente o contrato de "${contract.clientData?.fullName || contract.adminName}" da nuvem?`)) {
      await storageService.deleteContract(contract.id);
      navigate('/clientes');
    }
  };

  const handleToggleInactive = async () => {
    if (!contract) return;
    const isInactive = contract.paymentStatus === 'inactive';
    const newStatus: PaymentStatus = isInactive ? 'paid' : 'inactive';
    const updated = { ...contract, paymentStatus: newStatus };
    await storageService.saveContract(updated);
    setContract(updated);
  };

  if (isLoading) return (
    <div className="flex flex-col items-center justify-center min-h-[70vh]">
      <Clock className="animate-spin text-brand-green mb-4" size={40} />
      <p className="text-white/40 font-bold uppercase tracking-widest text-[10px]">Baixando da Nuvem...</p>
    </div>
  );

  if (!contract) return (
    <div className="flex flex-col items-center justify-center min-h-[70vh]">
      <AlertCircle className="text-red-400 mb-4" size={40} />
      <p className="text-white/40 font-bold uppercase">Contrato não encontrado.</p>
    </div>
  );

  const isInactive = contract.paymentStatus === 'inactive';

  return (
    <div className={`max-w-7xl mx-auto px-4 py-8 ${isInactive ? 'opacity-90' : ''}`}>
      {isPreparing && (
        <div className="fixed inset-0 z-[100] bg-brand-dark/95 flex flex-col items-center justify-center text-center p-6 no-print">
          <div className="w-16 h-16 border-4 border-brand-green border-t-transparent rounded-full animate-spin mb-6"></div>
          <h2 className="text-2xl font-bold text-brand-green mb-2">Contrato Blindado!</h2>
          <p className="text-white/80 max-w-sm mb-6">Sua cópia está sendo gerada agora...</p>
          <div className="bg-white/10 p-6 rounded-2xl border border-white/20 text-sm max-w-xs shadow-2xl">
            <p className="text-brand-green font-bold mb-3 uppercase tracking-widest text-[10px] flex items-center justify-center gap-2">
              <AlertCircle size={14} /> Importante
            </p>
            <p className="text-white/70 mb-4 text-center">Selecione <strong>"Salvar como PDF"</strong> para guardar seu contrato.</p>
            {showManualTrigger && (
              <button onClick={handleManualPrint} className="w-full bg-brand-green text-brand-dark font-bold py-3 rounded-xl flex items-center justify-center gap-2 hover:brightness-110 active:scale-95 transition-all">
                <Download size={18} /> Baixar Agora
              </button>
            )}
          </div>
        </div>
      )}

      <div className="no-print flex flex-col md:flex-row items-center justify-between mb-8 gap-4">
        <Link to={isAdmin ? "/clientes" : "/"} className="flex items-center gap-2 text-white/60 hover:text-white px-4 py-2 hover:bg-white/5 rounded-lg transition-all">
          <ChevronLeft /> {isAdmin ? "Lista de Clientes" : "Dashboard"}
        </Link>

        <div className="flex items-center gap-3 w-full md:w-auto">
          {isAdmin && (
            <>
              <button 
                onClick={handleToggleInactive}
                className={`flex-1 md:flex-initial px-6 py-4 rounded-xl flex items-center justify-center gap-2 font-bold transition-all border ${
                  isInactive 
                  ? 'bg-brand-green/20 text-brand-green border-brand-green/30' 
                  : 'bg-white/5 text-white/40 border-white/10 hover:text-white hover:bg-white/10'
                }`}
              >
                {isInactive ? <UserCheck size={20} /> : <UserX size={20} />}
                {isInactive ? 'Reativar Cliente' : 'Inativar Cliente'}
              </button>
              <button 
                onClick={handleDelete}
                className="px-4 py-4 rounded-xl flex items-center justify-center gap-2 font-bold bg-red-500/10 text-red-400 border border-red-500/20 hover:bg-red-500/20 transition-all"
                title="Excluir da Nuvem"
              >
                <Trash2 size={20} />
              </button>
            </>
          )}
          <button 
            onClick={handleManualPrint} 
            className="flex-1 md:flex-initial bg-brand-green text-brand-dark px-8 py-4 rounded-xl flex items-center justify-center gap-2 font-bold hover:scale-105 active:scale-95 transition-transform shadow-xl shadow-brand-green/30"
          >
            <Download size={20} /> Baixar PDF
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        <div className="lg:col-span-3">
          <div className={isInactive ? 'grayscale-[0.4]' : ''}>
            <ContractPreview 
              {...contract}
              clientData={contract.clientData}
              signature={contract.signatureImage}
              signedAt={contract.signedAt}
              metadata={contract.metadata}
            />
          </div>
        </div>

        <div className="no-print space-y-6">
          <div className={`border rounded-2xl p-6 transition-all ${isInactive ? 'bg-white/5 border-white/10' : 'bg-brand-green/10 border-brand-green/20'}`}>
            <h3 className={`font-bold flex items-center gap-2 mb-4 uppercase tracking-widest text-xs ${isInactive ? 'text-white/40' : 'text-brand-green'}`}>
              <ShieldCheck size={18} /> {isInactive ? 'Cadastro Inativo' : 'Validação Técnica'}
            </h3>
            <div className="space-y-4 text-sm text-white">
              <div className="pb-4 border-b border-white/10">
                <label className="block text-white/40 mb-1 uppercase text-[10px] font-bold">Status Atual</label>
                <div className={`font-bold text-xl uppercase ${isInactive ? 'text-white/40' : 'text-brand-green'}`}>
                  {isInactive ? 'Serviço Suspenso' : 'Documento Blindado'}
                </div>
              </div>
              <div className="flex items-start gap-3">
                <Calendar className="text-white/40 mt-1" size={16} />
                <div className="text-left">
                  <label className="block text-white/40 uppercase text-[10px] font-bold">Data Assinatura</label>
                  <div className="text-white/90">{contract.signedAt}</div>
                </div>
              </div>
              <div className="flex items-start gap-3">
                <Globe className="text-white/40 mt-1" size={16} />
                <div className="text-left">
                  <label className="block text-white/40 uppercase text-[10px] font-bold">IP de Registro</label>
                  <div className="font-mono text-xs text-white/90">{contract.metadata?.ip}</div>
                </div>
              </div>
              {contract.finalSystemLink && (
                <div className="pt-4 mt-4 border-t border-white/10">
                   <a 
                    href={contract.finalSystemLink} 
                    target="_blank" 
                    rel="noreferrer"
                    className="flex items-center justify-center gap-2 w-full py-3 bg-brand-blue/10 text-brand-blue border border-brand-blue/20 rounded-xl font-bold hover:bg-brand-blue/20 transition-all text-xs uppercase tracking-widest"
                   >
                     Acessar Sistema <Globe size={14} />
                   </a>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ContractDetail;

